class Transaction {
    var id: Int
    var date: Date
    var type: String
    var amount: Double
    
    init(id: Int, date: Date, type: String, amount: Double) {
        self.id = id
        self.date = date
        self.type = type
        self.amount = amount
    }
}

class Account {
    var balance: Double
    var transactions: [Transaction]
    
    init(balance: Double) {
        self.balance = balance
        self.transactions = []
    }
    
    func deposit(amount: Double) {
        balance += amount
        let transaction = Transaction(id: transactions.count, date: Date(), type: "Deposit", amount: amount)
        transactions.append(transaction)
    }
    
    func withdraw(amount: Double) {
        if balance >= amount {
            balance -= amount
            let transaction = Transaction(id: transactions.count, date: Date(), type: "Withdrawal", amount: amount)
            transactions.append(transaction)
        } else {
            print("Insufficient funds")
        }
    }
}

class SecureStore {
    private var store: URL
    
    init(storeName: String) {
        let documentsDirectory = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first!
        self.store = documentsDirectory.appendingPathComponent(storeName)
        
        do {
            try FileManager.default.createDirectory(atPath: store.path, withIntermediateDirectories: false)
        } catch {}
    }
    
    func encrypt(_ data: Data) -> Data? {
        let encryptionKey = "myEncryptionKey"
        let encryptedData = try! SymmetricKey(data: Data(hexString: encryptionKey)!)
            .encryptor()
            .encrypt(data, withPadding: true)
        
        return encryptedData
    }
    
    func decrypt(_ data: Data?) -> Data? {
        guard let data = data else { return nil }
        
        let encryptionKey = "myEncryptionKey"
        let decryptedData = try! SymmetricKey(data: Data(hexString: encryptionKey)!)
            .decryptor()
            .decrypt(data)
        
        return decryptedData
    }
    
    func save(_ data: Data, forKey key: String) {
        guard let encryptedData = encrypt(data) else { return }
        
        do {
            try FileManager.default.createFile(atPath: store.appendingPathComponent(key).path, contents: encryptedData)
        } catch {}
    }
    
    func load(forKey key: String) -> Data? {
        if let data = FileManager.default.contentsAtURL(store.appendingPathComponent(key)) {
            return decrypt(data)
        } else {
            return nil
        }
    }
}

